// Story 7.4 AC1 + AC3: per-email Message-ID dedup.
// Hash the RFC 5322 Message-ID header and check against the
// `linkedin_email.seen_message_ids` static-data slot. Drop if seen.
//
// FR10 + FR11 + NFR12: this flow never fetches linkedin.com.
// Only the email payload is read; the Message-ID is taken from the
// email's own headers — no LinkedIn site hit.
const crypto = require('crypto');

const staticData = this.getWorkflowStaticData('global');
if (!staticData.linkedin_email) {
  staticData.linkedin_email = { seen_message_ids: {}, seen_job_urls: {} };
}
if (!staticData.linkedin_email.seen_message_ids) {
  staticData.linkedin_email.seen_message_ids = {};
}

const out = [];
for (const item of items) {
  const headers = (item.json && item.json.headers) || {};
  // RFC 5322 Message-ID header — case can vary by IMAP server.
  const messageId =
    headers['message-id'] ||
    headers['Message-ID'] ||
    headers['Message-Id'] ||
    (item.json && item.json.messageId) ||
    '';
  if (!messageId) {
    // No Message-ID — log and skip; do not crash the flow.
    console.warn('linkedin_email: email has no Message-ID header; skipping');
    continue;
  }
  const hash = crypto.createHash('sha256').update(String(messageId)).digest('hex');
  if (staticData.linkedin_email.seen_message_ids[hash]) {
    // Already processed this email — drop silently.
    continue;
  }
  // Mark provisionally as seen so we don't re-parse on the same poll batch.
  staticData.linkedin_email.seen_message_ids[hash] = new Date().toISOString();
  out.push({
    json: {
      ...item.json,
      _message_id: messageId,
      _message_id_hash: hash,
      _email_received_at: (item.json && (item.json.date || item.json.receivedDate)) || new Date().toISOString(),
    },
  });
}
return out;

// Story 7.4 AC2: parse LinkedIn's Job Alert email template.
// Pulls each job block from the email body (HTML preferred, plain-text fallback)
// and emits one item per job with: job_title, company, linkedin_job_url, jd_text.
//
// FR10 + FR11 + NFR12: the parser reads the email body ONLY.
// It NEVER follows links, NEVER opens a browser, NEVER hits linkedin.com.
// LinkedIn tracking URLs are captured AS-IS — resolution happens downstream.
const out = [];
for (const item of items) {
  const body = item.json || {};
  const html = body.html || body.textHtml || '';
  const text = body.text || body.textPlain || '';
  const blocks = [];
  if (html && typeof html === 'string' && html.length > 0) {
    // LinkedIn Job Alert HTML emails wrap each job in an anchor that points
    // to a LinkedIn tracking URL (linkedin.com/comm/jobs/view/... or similar).
    // We capture each anchor as-is — no site fetch is performed against it.
    const anchorRegex = /<a[^>]+href="([^"]+)"[^>]*>([\s\S]*?)<\/a>/gi;
    const seenUrls = new Set();
    let match;
    while ((match = anchorRegex.exec(html)) !== null) {
      const url = match[1];
      const innerHtml = match[2] || '';
      const innerText = innerHtml.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
      // Heuristic: a job-card anchor's inner text looks like a job title and
      // the href contains a /jobs/view/ or /comm/jobs/view/ path segment.
      // We do NOT fetch the URL — we just capture it as data.
      if (
        innerText &&
        innerText.length >= 3 &&
        /jobs\/view\//i.test(url) &&
        !seenUrls.has(url)
      ) {
        seenUrls.add(url);
        blocks.push({
          job_title: innerText,
          company: '',
          linkedin_job_url: url,
          surrounding_snippet_text: innerText,
        });
      }
    }
  }
  if (blocks.length === 0 && text && typeof text === 'string') {
    // Plain-text fallback. LinkedIn Job Alert plain-text bodies list each
    // posting on its own block: title line, company/location line, then URL.
    const urlRegex = /(https?:\/\/[^\s)>\]]+)/g;
    const urls = text.match(urlRegex) || [];
    const seenUrls = new Set();
    for (const url of urls) {
      if (!/jobs\/view\//i.test(url)) {
        continue;
      }
      if (seenUrls.has(url)) {
        continue;
      }
      seenUrls.add(url);
      const idx = text.indexOf(url);
      const start = Math.max(0, idx - 240);
      const end = Math.min(text.length, idx + url.length + 80);
      const snippet = text.slice(start, end).replace(/\s+/g, ' ').trim();
      blocks.push({
        job_title: '',
        company: '',
        linkedin_job_url: url,
        surrounding_snippet_text: snippet,
      });
    }
  }
  if (blocks.length === 0) {
    // AC2: zero parsable blocks => template drift. Log warning, skip email,
    // do NOT crash the flow.
    console.warn(
      'linkedin_email: template-drift — zero parsable job blocks in email',
      { message_id: body._message_id, received_at: body._email_received_at }
    );
    continue;
  }
  for (const block of blocks) {
    out.push({
      json: {
        ...block,
        _message_id: body._message_id,
        _message_id_hash: body._message_id_hash,
        _email_received_at: body._email_received_at,
      },
    });
  }
}
return out;

// Story 7.4 AC3: per-extracted-URL dedup (scoped to `linkedin_email`).
// Hash each extracted job URL with SHA-256 and check against the
// `linkedin_email.seen_job_urls` static-data slot. Drop if already seen.
//
// FR10 + FR11 + NFR12: dedup is done in-memory on the URL string only.
// The flow does NOT fetch the URL to canonicalize it — site crawling against
// linkedin.com is forbidden by inspection.
const crypto = require('crypto');

const staticData = this.getWorkflowStaticData('global');
if (!staticData.linkedin_email) {
  staticData.linkedin_email = { seen_message_ids: {}, seen_job_urls: {} };
}
if (!staticData.linkedin_email.seen_job_urls) {
  staticData.linkedin_email.seen_job_urls = {};
}

const out = [];
for (const item of items) {
  const url = (item.json && item.json.linkedin_job_url) || '';
  if (!url) {
    continue;
  }
  const hash = crypto.createHash('sha256').update(String(url)).digest('hex');
  if (staticData.linkedin_email.seen_job_urls[hash]) {
    // Already POSTed in a prior run — drop silently.
    continue;
  }
  out.push({
    json: {
      ...item.json,
      _url_hash: hash,
    },
  });
}
return out;

// Story 7.4 AC4: build the canonical /api/paste body per docs/n8n-contract.md.
// source = 'linkedin_email'. jd_text = the surrounding snippet (the JD blurb
// LinkedIn embeds in the email). url = the linkedin job URL captured as-is
// from the email (not fetched). discovered_at = ISO-8601 UTC of email receipt.
const out = [];
for (const item of items) {
  const j = item.json || {};
  const discoveredAt = j._email_received_at
    ? new Date(j._email_received_at).toISOString()
    : new Date().toISOString();
  out.push({
    json: {
      source: 'linkedin_email',
      jd_text: j.surrounding_snippet_text || j.job_title || '',
      url: j.linkedin_job_url || '',
      discovered_at: discoveredAt,
      _url_hash: j._url_hash,
      _message_id_hash: j._message_id_hash,
    },
  });
}
return out;

// Story 7.4 AC3 + AC4: on 2xx, record BOTH the URL hash AND the
// Message-ID hash. Non-2xx leaves the hashes unrecorded so the next IMAP
// poll re-attempts the POST.
const staticData = this.getWorkflowStaticData('global');
if (!staticData.linkedin_email) {
  staticData.linkedin_email = { seen_message_ids: {}, seen_job_urls: {} };
}
if (!staticData.linkedin_email.seen_job_urls) {
  staticData.linkedin_email.seen_job_urls = {};
}
if (!staticData.linkedin_email.seen_message_ids) {
  staticData.linkedin_email.seen_message_ids = {};
}

const now = new Date().toISOString();
for (const item of items) {
  const body = (item.json && item.json.body) || item.json || {};
  // The HTTP Request node with fullResponse=true emits { body, headers, statusCode }.
  // We pull the original request fields from $json.body when they're nested.
  const urlHash = body._url_hash || (item.json && item.json._url_hash);
  const messageIdHash = body._message_id_hash || (item.json && item.json._message_id_hash);
  if (urlHash) {
    staticData.linkedin_email.seen_job_urls[urlHash] = now;
  }
  if (messageIdHash) {
    staticData.linkedin_email.seen_message_ids[messageIdHash] = now;
  }
}
return items;
